#define OPEN
#define	ITERATION
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime_api.h>

void random_matrix(float *I, int rows, int cols);

__global__ void srad_step1_kernel(
    const float *J, float *dN, float *dS, float *dW, float *dE, float *c,
    int rows, int cols,
    const int *iN, const int *iS, const int *jW, const int *jE,
    float q0sqr)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rows && j < cols) {
        int k = i * cols + j;
        float Jc = J[k];

        float dN_val = J[iN[i] * cols + j] - Jc;
        float dS_val = J[iS[i] * cols + j] - Jc;
        float dW_val = J[i * cols + jW[j]] - Jc;
        float dE_val = J[i * cols + jE[j]] - Jc;

        dN[k] = dN_val;
        dS[k] = dS_val;
        dW[k] = dW_val;
        dE[k] = dE_val;

        float G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        float L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
        float den = 1.0f + 0.25f * L;
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        c[k] = c_val;
    }
}

__global__ void srad_step2_kernel(
    float *J, const float *c, const float *dN, const float *dS, const float *dW, const float *dE,
    int rows, int cols,
    const int *iS, const int *jE,
    float lambda)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rows && j < cols) {
        int k = i * cols + j;

        float cN = c[k];
        float cS = c[iS[i] * cols + j];
        float cW = c[k];
        float cE = c[i * cols + jE[j]];

        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

        J[k] = J[k] + 0.25f * lambda * D;
    }
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> 	 - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

	exit(1);
}

int main(int argc, char* argv[])
{   
	int rows, cols, size_I, size_R, niter = 10, iter, k;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI,varROI ;
	float Jc, G2, L, num, den, qsqr;
	int *iN,*iS,*jE,*jW;
	float *dN,*dS,*dW,*dE;
	int r1, r2, c1, c2;
	float cN,cS,cW,cE;
	float *c, D;
	float lambda;
	int i, j;
    int nthreads;

	if (argc == 10)
	{
		rows = atoi(argv[1]); 
		cols = atoi(argv[2]); 
		if ((rows%16!=0) || (0 != cols%16)){
			fprintf(stderr, "rows and cols must be multiples of 16\n");
			exit(1);
		}
		r1   = atoi(argv[3]); 
		r2   = atoi(argv[4]); 
		c1   = atoi(argv[5]); 
		c2   = atoi(argv[6]); 
		nthreads = atoi(argv[7]); 
		lambda = atof(argv[8]); 
		niter = atoi(argv[9]); 
	}
    else{
		usage(argc, argv);
    }


	size_I = cols * rows;
    size_R = (r2-r1+1)*(c2-c1+1);   

	I = (float *)malloc( size_I * sizeof(float) );
    J = (float *)malloc( size_I * sizeof(float) );
	c  = (float *)malloc(sizeof(float)* size_I) ;

    iN = (int *)malloc(sizeof(int) * rows) ;
    iS = (int *)malloc(sizeof(int) * rows) ;
    jW = (int *)malloc(sizeof(int) * cols) ;
    jE = (int *)malloc(sizeof(int) * cols) ;    


	dN = (float *)malloc(sizeof(float)* size_I) ;
    dS = (float *)malloc(sizeof(float)* size_I) ;
    dW = (float *)malloc(sizeof(float)* size_I) ;
    dE = (float *)malloc(sizeof(float)* size_I) ;    


    for (int i=0; rows > i; i++) {
        iN[i] = i-1;
        iS[i] = i+1;
    }    
    for (int j=0; cols > j; j++) {
        jW[j] = j-1;
        jE[j] = j+1;
    }
    iN[0]    = 0;
    iS[rows-1] = rows-1;
    jW[0]    = 0;
    jE[cols-1] = cols-1;

	printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (k = 0;  size_I > k; k++ ) {
     	J[k] = (float)exp(I[k]) ;
    }

	printf("Start the SRAD main loop\n");

    // Allocate device memory
    float *d_J, *d_c, *d_dN, *d_dS, *d_dW, *d_dE;
    int *d_iN, *d_iS, *d_jW, *d_jE;

    cudaMalloc((void**)&d_J, size_I * sizeof(float));
    cudaMalloc((void**)&d_c, size_I * sizeof(float));
    cudaMalloc((void**)&d_dN, size_I * sizeof(float));
    cudaMalloc((void**)&d_dS, size_I * sizeof(float));
    cudaMalloc((void**)&d_dW, size_I * sizeof(float));
    cudaMalloc((void**)&d_dE, size_I * sizeof(float));

    cudaMalloc((void**)&d_iN, rows * sizeof(int));
    cudaMalloc((void**)&d_iS, rows * sizeof(int));
    cudaMalloc((void**)&d_jW, cols * sizeof(int));
    cudaMalloc((void**)&d_jE, cols * sizeof(int));

    cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_iN, iN, rows * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_iS, iS, rows * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_jW, jW, cols * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_jE, jE, cols * sizeof(int), cudaMemcpyHostToDevice);

    dim3 blockDim(16, 16);
    dim3 gridDim((cols + blockDim.x - 1) / blockDim.x, (rows + blockDim.y - 1) / blockDim.y);

#ifdef ITERATION
	for (iter=0; niter > iter; iter++){
#endif        
		sum=0; sum2=0;     
		for (i=r1; i<=r2; i++) {
            for (j=c1; c2 >= j; j++) {
                tmp   = J[i * cols + j];
                sum = sum + (tmp) ;
                sum2 += tmp*tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI*meanROI;
        q0sqr   = varROI / (meanROI*meanROI);


        // Step 1 kernel
        srad_step1_kernel<<<gridDim, blockDim>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c,
            rows, cols, d_iN, d_iS, d_jW, d_jE, q0sqr);
        cudaDeviceSynchronize();

        // Step 2 kernel
        srad_step2_kernel<<<gridDim, blockDim>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE,
            rows, cols, d_iS, d_jE, lambda);
        cudaDeviceSynchronize();

#ifdef ITERATION
	}
#endif

    cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost);

#ifdef OUTPUT
	  for( int i = 0 ; i < rows ; i++){
		for ( int j = 0 ; j < cols ; j++){

         printf("%.5f ", J[i * cols + j]); 

		}
         printf("\n"); 
   }
#endif 

	printf("Computation Done\n");

	free(I);
	free(J);
	free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);

	free(c);

    cudaFree(d_J);
    cudaFree(d_c);
    cudaFree(d_dN);
    cudaFree(d_dS);
    cudaFree(d_dW);
    cudaFree(d_dE);
    cudaFree(d_iN);
    cudaFree(d_iS);
    cudaFree(d_jW);
    cudaFree(d_jE);

	return 0;
}




void random_matrix(float *I, int rows, int cols){

	srand(7);

	for( int i = 0 ; i < rows ; i++){
		for ( int j = 0 ; cols > j ; j++){
		 I[i * cols + j] = rand()/(float)RAND_MAX ;
		}
	}

}
